var BIBLE_CHARACTERS=[
{id:"adam",name:"Adam",ta_name:"ஆதாம்",emoji:"🌿",color:"#1a6b3c",era:"Creation",testament:"OT",
 tagline_en:"The First Man God Created",tagline_ta:"தேவன் படைத்த முதல் மனிதன்",
 summary_en:"Long, long ago, before anything existed, God made the whole world! He made the bright sun, the shining moon, and millions of twinkling stars. He made tall mountains, wide oceans, and beautiful gardens full of flowers and fruit trees. Then God made all the animals — lions, elephants, butterflies, and tiny little ants! Everything was wonderful and perfect. But God wanted someone special to love and talk with. So He scooped up dust from the ground, shaped it into a man, and breathed life into his nose. The man opened his eyes and looked around at the beautiful world. God named him Adam. Adam lived in the most wonderful garden called Eden. Every morning he walked with God among the flowers and trees. Adam named all the animals — he called one big grey animal 'elephant' and a tiny hopping one 'rabbit'! But Adam was lonely. So God made a woman from Adam's rib and named her Eve. They were so happy together! God gave them one rule: never eat from the special tree in the middle of the garden. One day a sneaky serpent told Eve the fruit was delicious. She ate it, and gave some to Adam too. At once they felt ashamed and hid. God called out: 'Adam, where are you?' God was sad they had disobeyed, but He still loved them. He made warm clothes for them and promised that one day, a Saviour would come to fix everything that went wrong.",
 summary_ta:"மிக மிக முன்பு, இந்த உலகில் எதுவும் இல்லாத போது, தேவன் எல்லாவற்றையும் படைத்தார்! சூரியன், சந்திரன், நட்சத்திரங்கள், மலைகள், கடல்கள், அழகான தோட்டங்கள் — எல்லாவற்றையும் படைத்தார். பிறகு சகல மிருகங்களையும் படைத்தார். ஆனால் தேவனுக்கு ஒரு நெருங்கிய நண்பன் வேண்டும். அதனால் பூமியின் மண்ணை எடுத்து ஒரு மனிதனை உருவாக்கினார், அவன் மூக்கில் ஊதினார், அவன் உயிர் பெற்றான்! அவன் பெயர் ஆதாம். ஆதாம் ஏதேன் தோட்டத்தில் வாழ்ந்தான். ஒவ்வொரு நாளும் தேவனோடு நடந்தான். அனைத்து மிருகங்களுக்கும் பெயர் சூட்டினான். ஆனால் தேவன் ஒரு முக்கியமான கட்டளை கொடுத்தார்: நடு தோட்டத்தில் உள்ள மரத்தின் பழத்தை சாப்பிடாதே! ஒரு நாள் தந்திரமான பாம்பு ஏவாளை ஏமாற்றியது. அவள் பழம் சாப்பிட்டாள், ஆதாமும் சாப்பிட்டான். உடனே அவர்கள் வெட்கப்பட்டார்கள். தேவன் அவர்களை தேடி வந்தார். தேவன் துக்கப்பட்டார், ஆனாலும் அவர்களை நேசித்தார். அவர்களுக்கு ஆடைகள் கொடுத்தார், ஒரு மீட்பர் வருவார் என்று வாக்குறுதி அளித்தார்.",
 timeline:[
  {ref:"Gen 1:27",en:"God created Adam from the dust of the earth",ta:"தேவன் மண்ணிலிருந்து ஆதாமை படைத்தார்"},
  {ref:"Gen 2:7",en:"God breathed life into Adam's nostrils",ta:"தேவன் ஆதாமின் மூக்கில் உயிரை ஊதினார்"},
  {ref:"Gen 2:15",en:"Adam placed in the Garden of Eden to take care of it",ta:"ஏதேன் தோட்டத்தை பராமரிக்க ஆதாம் வைக்கப்பட்டார்"},
  {ref:"Gen 2:19",en:"Adam named all the animals and birds",ta:"ஆதாம் சகல மிருகங்களுக்கும் பெயர் சூட்டினார்"},
  {ref:"Gen 2:22",en:"Eve created as Adam's companion",ta:"ஏவாள் ஆதாமின் துணையாக படைக்கப்பட்டாள்"},
  {ref:"Gen 3:6",en:"Adam and Eve ate the forbidden fruit",ta:"ஆதாமும் ஏவாளும் தடைப்பட்ட பழம் சாப்பிட்டார்கள்"},
  {ref:"Gen 3:9",en:"God calls out: 'Adam, where are you?'",ta:"தேவன் கூப்பிட்டார்: 'ஆதாமே, நீ எங்கே?'"},
  {ref:"Gen 3:15",en:"God promises a Saviour who will crush the serpent",ta:"மீட்பர் வருவார் என்று தேவன் வாக்குறுதி அளித்தார்"},
  {ref:"Gen 3:21",en:"God made clothes from animal skins for Adam and Eve",ta:"தேவன் அவர்களுக்கு தோலினால் ஆடை செய்தார்"},
  {ref:"Gen 5:5",en:"Adam lived 930 years",ta:"ஆதாம் 930 ஆண்டுகள் வாழ்ந்தார்"}
 ],
 verses:[
  {ref:"Genesis 1:27",en:"God created man in His own image; male and female He created them.",ta:"தேவன் மனிதனை தம்முடைய சாயலில் படைத்தார்; ஆணும் பெண்ணுமாக படைத்தார்."},
  {ref:"Genesis 2:7",en:"God formed man of dust from the ground and breathed into his nostrils the breath of life.",ta:"தேவன் பூமியின் மண்ணால் மனிதனை உருவாக்கி, அவன் மூக்கில் உயிர் மூச்சை ஊதினார்."},
  {ref:"Genesis 3:15",en:"I will put enmity between you and the woman; her offspring shall bruise your head.",ta:"உனக்கும் அவளுக்கும் பகையை வைப்பேன்; அவளுடைய சந்ததி உன் தலையை நசுக்கும்."},
  {ref:"Romans 5:12",en:"Sin entered the world through one man, and death through sin.",ta:"ஒரு மனிதனால் பாவம் உலகில் வந்தது, பாவத்தால் மரணம் வந்தது."},
  {ref:"1 Corinthians 15:22",en:"For as in Adam all die, so also in Christ shall all be made alive.",ta:"ஆதாமில் எல்லாரும் மரிக்கிறதுபோல, கிறிஸ்துவிலும் எல்லாரும் உயிரடைவார்கள்."}
 ],
 lessons_en:[
  "God made you wonderfully special — you are created in His image and He loves you very much!",
  "Obedience matters — Adam and Eve's one act of disobedience changed everything, showing how important it is to listen to God.",
  "God always comes looking for us — even when we do wrong and hide, God calls out to find us because He loves us.",
  "Sin has consequences — but God is so kind that He provided clothes for Adam and Eve and promised a Saviour.",
  "Hope always remains — even in the saddest moment, God gave a beautiful promise that Jesus would one day come and fix everything."
 ],
 lessons_ta:[
  "தேவன் உன்னை அற்புதமாக படைத்தார் — நீ அவருடைய சாயலில் படைக்கப்பட்டாய்!",
  "கீழ்ப்படிதல் முக்கியம் — ஆதாமின் ஒரு தவறான தேர்வு எல்லாவற்றையும் மாற்றியது.",
  "தேவன் தேடி வருகிறார் — நாம் தவறு செய்து ஒளிந்தாலும் தேவன் நம்மை தேடுகிறார்.",
  "பாவத்திற்கு விளைவுகள் உண்டு — ஆனால் தேவன் இரக்கமுள்ளவர், அவர் உதவுகிறார்.",
  "நம்பிக்கை எப்போதும் இருக்கிறது — தேவன் ஒரு மீட்பர் அனுப்புவார் என்று வாக்குறுதி அளித்தார்."
 ]
},
{id:"noah",name:"Noah",ta_name:"நோவா",emoji:"🌈",color:"#1a4a8a",era:"Flood",testament:"OT",
 tagline_en:"The Man Who Built a Giant Boat",tagline_ta:"பெரிய பேழை கட்டிய மனிதன்",
 summary_en:"Many years after Adam and Eve, the world became full of bad people who did terrible things. God was very sad. But there was one good man named Noah who loved God and tried to do right. God told Noah a big secret: He was going to send a great flood to wash the world clean. God told Noah to build a giant boat called an ark — big enough for his whole family and two of every animal on earth! Noah's neighbours laughed at him. 'A boat? Here on dry land? You are crazy!' they said. But Noah kept working, day after day, year after year, hammering and sawing. He trusted God completely. When the ark was finally finished, something amazing happened — animals came walking, crawling, hopping and flying from everywhere! Two by two they came into the ark. Noah's family went in too. Then the rain began to fall. It rained for forty days and forty nights! The whole earth was covered with water. But inside the ark, Noah and his family and all the animals were safe and cozy. After many days, Noah sent out a dove. The dove came back with an olive branch in its beak — dry land was near! When they finally came out, Noah built an altar and thanked God. Then God put a beautiful rainbow in the sky. 'This rainbow is my promise,' said God. 'I will never flood the whole earth again.' Every time you see a rainbow, remember God keeps His promises!",
 summary_ta:"ஆதாமுக்கு பின்னர் உலகம் கெட்டுப்போனது. எல்லாரும் தீமை செய்தார்கள். தேவன் மிகவும் வருந்தினார். ஆனால் நோவா என்று ஒரு நல்ல மனிதன் இருந்தான். தேவன் நோவாவிடம் சொன்னார்: 'ஒரு பெரிய பேழை கட்டு! உன் குடும்பமும் எல்லா மிருகங்களும் அதில் ஏறட்டும்.' நோவாவின் அண்டை வீட்டார் சிரித்தார்கள். 'இந்த இடத்தில் படகு கட்டுகிறாயா? நீ பைத்தியம்!' என்றார்கள். ஆனால் நோவா தினமும் வேலை செய்தான். தேவனை நம்பினான். பேழை தயாரானது. எங்கிருந்தோ மிருகங்கள் இரண்டிரண்டாக வந்தன — பெரிய யானைகளும், சிறிய எறும்புகளும், அழகான பறவைகளும்! நோவாவின் குடும்பமும் ஏறியது. மழை பெய்யத் தொடங்கியது — நாற்பது நாள் நாற்பது இரவு! உலகமே தண்ணீரில் மூழ்கியது. ஆனால் பேழைக்கு உள்ளே எல்லாரும் பாதுகாப்பாக இருந்தார்கள். நோவா ஒரு புறாவை விட்டான். அது ஒலிவ் மரத்தின் கிளையோடு திரும்பியது! தரை தெரிந்தது! வெளியே வந்து நோவா தேவனுக்கு நன்றி சொன்னான். தேவன் வானவில் வைத்தார். 'இது என்னுடைய வாக்குறுதி — இனி உலகை தண்ணீரால் அழிக்கமாட்டேன்' என்றார். நீ வானவில் பார்க்கும்போது நினைத்துக்கொள் — தேவன் வாக்குறுதி காக்கிறார்!",
 timeline:[
  {ref:"Gen 6:9",en:"Noah was a righteous man who walked with God",ta:"நோவா நீதிமான், தேவனோடு நடந்தான்"},
  {ref:"Gen 6:14",en:"God tells Noah to build the ark",ta:"தேவன் நோவாவிடம் பேழை கட்ட சொன்னார்"},
  {ref:"Gen 7:1",en:"God invites Noah's family and the animals into the ark",ta:"தேவன் நோவாவின் குடும்பத்தையும் மிருகங்களையும் பேழைக்குள் அழைத்தார்"},
  {ref:"Gen 7:12",en:"Rain falls for forty days and forty nights",ta:"நாற்பது நாளும் இரவும் மழை பெய்தது"},
  {ref:"Gen 7:17",en:"The flood covers the whole earth",ta:"வெள்ளம் முழு பூமியையும் மூடியது"},
  {ref:"Gen 8:6",en:"Noah sends out a raven and a dove",ta:"நோவா காகத்தையும் புறாவையும் விட்டான்"},
  {ref:"Gen 8:11",en:"The dove returns with an olive branch",ta:"புறா ஒலிவ் கிளையோடு திரும்பியது"},
  {ref:"Gen 8:18",en:"Noah's family and all animals leave the ark",ta:"நோவாவின் குடும்பமும் மிருகங்களும் பேழையை விட்டு வெளியே வந்தன"},
  {ref:"Gen 8:20",en:"Noah builds an altar and worships God",ta:"நோவா பலிபீடம் கட்டி தேவனை தொழுதான்"},
  {ref:"Gen 9:13",en:"God places a rainbow in the clouds as His promise",ta:"தேவன் மேகத்தில் வானவில் வைத்தார்"}
 ],
 verses:[
  {ref:"Genesis 6:9",en:"Noah was a righteous man, blameless in his generation. Noah walked with God.",ta:"நோவா தன் தலைமுறையில் நீதிமானும் உத்தமனுமாய் இருந்தான். தேவனோடு நடந்தான்."},
  {ref:"Genesis 7:1",en:"The LORD said to Noah: Go into the ark, you and all your household, for I have seen that you are righteous before me.",ta:"கர்த்தர் நோவாவிடம்: நீயும் உன் வீட்டாரும் பேழைக்குள் பிரவேசியுங்கள்."},
  {ref:"Genesis 9:13",en:"I have set my rainbow in the clouds, and it will be the sign of the covenant between me and the earth.",ta:"மேகத்தில் என் வில்லை வைக்கிறேன், அது என்னுக்கும் பூமிக்கும் இடையே உடன்படிக்கையின் அடையாளமாக இருக்கும்."},
  {ref:"Hebrews 11:7",en:"By faith Noah built an ark for the saving of his household.",ta:"விசுவாசத்தினால் நோவா தன் வீட்டாரை இரட்சிக்கும்படி பேழை கட்டினான்."},
  {ref:"2 Peter 2:5",en:"God preserved Noah, a herald of righteousness.",ta:"தேவன் நீதியை பிரசங்கித்த நோவாவை காப்பாற்றினார்."}
 ],
 lessons_en:[
  "God notices good people — in a world full of wickedness, God saw Noah's faithfulness and chose him for something special.",
  "Trust and obey even when others laugh — Noah kept building even when everyone mocked him, because he trusted God completely.",
  "God protects those who follow Him — inside the ark, God kept every creature safe through the storm.",
  "After every storm comes a rainbow — God always brings something beautiful after hard times.",
  "God keeps His promises — the rainbow is still in the sky today, reminding us that God never breaks His word!"
 ],
 lessons_ta:[
  "தேவன் நல்லவர்களை கவனிக்கிறார் — ஒரு கெட்ட உலகில் நோவாவின் நம்பிக்கையை தேவன் பார்த்தார்.",
  "மற்றவர்கள் சிரித்தாலும் தேவனை நம்பு — நோவா அனைவரும் கேலி செய்தாலும் பேழை கட்டினான்.",
  "தேவனை பின்பற்றுவோரை அவர் காக்கிறார் — புயலிலும் பேழையில் அனைவரும் பாதுகாப்பாக இருந்தார்கள்.",
  "ஒவ்வொரு புயலுக்கும் பின் வானவில் வரும் — தேவன் கஷ்டத்திற்கு பின்னர் அழகான ஆசீர்வாதம் தருகிறார்.",
  "தேவன் வாக்குறுதிகளை காக்கிறார் — வானவில் இன்றும் நம்மை நினைவுபடுத்துகிறது."
 ]
},
{id:"abraham",name:"Abraham",ta_name:"ஆபிரகாம்",emoji:"⭐",color:"#8a6a1a",era:"Patriarchs",testament:"OT",
 tagline_en:"The Father of Faith",tagline_ta:"விசுவாசத்தின் தந்தை",
 summary_en:"Abraham lived in a big city called Ur, full of people who worshipped false gods. But God spoke to Abraham one day and said something amazing: 'Leave your home and go to a land I will show you. I will make your family into a great nation, and through you all families of the earth will be blessed!' Abraham was already 75 years old! But he trusted God and packed up everything. With his wife Sarah, his nephew Lot, and all their servants, Abraham set out on a great adventure — not even knowing where he was going! God guided them all the way to the land of Canaan. God said: 'One day, all this land will belong to your children.' But Abraham had no children! He was getting very old and so was Sarah. Could God really keep such a big promise? Years passed. Abraham often looked up at the night sky full of stars. God said: 'Count the stars if you can — that is how many children and grandchildren and great-grandchildren you will have!' Abraham believed God, even when it seemed impossible. Then, when Abraham was 100 years old and Sarah was 90, a baby boy was born! They named him Isaac, which means 'laughter' — because Sarah laughed with joy! Abraham's greatest test came when God asked him to sacrifice Isaac on a mountain. Abraham trusted God completely and obeyed. But just in time, God stopped him and provided a ram instead. Abraham passed the test! God said: 'Now I know you trust me completely.' Today, billions of people are called children of Abraham — Jews, Christians, and Muslims all trace their faith back to this one faithful man.",
 summary_ta:"ஆபிரகாம் உர் என்னும் பெரிய நகரில் வாழ்ந்தான். ஒரு நாள் தேவன் பேசினார்: 'உன் வீட்டை விட்டு புறப்படு! நான் காட்டும் தேசத்திற்கு போ. உன்னிலிருந்து ஒரு பெரிய ஜாதி உண்டாகும்!' ஆபிரகாமுக்கு 75 வயது! ஆனாலும் தேவனை நம்பி தன் மனைவி சாராளோடு, மேலும் சேவகரோடு புறப்பட்டான். எங்கே போகிறோம் என்று கூட தெரியாமல் நடந்தான்! தேவன் அவனை கானான் தேசத்திற்கு வழிநடத்தினார். ஆண்டுகள் கடந்தன. ஆபிரகாமுக்கு குழந்தை இல்லை. ஒரு இரவு தேவன் சொன்னார்: 'வானத்தை பார். நட்சத்திரங்களை எண்ண முடியுமா? உன் பிள்ளைகள் அவ்வளவு பேர் இருப்பார்கள்!' ஆபிரகாம் நம்பினான். ஆபிரகாமுக்கு 100 வயது, சாராளுக்கு 90 வயது ஆனபோது — ஒரு குழந்தை பிறந்தது! அதற்கு ஈசாக்கு என்று பெயரிட்டார்கள். அதாவது 'சிரிப்பு' — சாரா சந்தோஷத்தில் சிரித்தாள்! ஒரு நாள் தேவன் கடினமான கட்டளை கொடுத்தார்: ஈசாக்கை பலியிட. ஆபிரகாம் கீழ்படிந்தான். ஆனால் கடைசி நிமிடம் தேவன் தடுத்தார், ஒரு ஆட்டை கொடுத்தார். 'இப்போது தெரிகிறது நீ என்னை நம்புகிறாய்' என்றார். ஆபிரகாம் இன்றும் 'விசுவாசத்தின் தந்தை' என்று அழைக்கப்படுகிறான்.",
 timeline:[
  {ref:"Gen 12:1",en:"God calls Abraham to leave Ur for an unknown land",ta:"தேவன் ஆபிரகாமை அறியாத தேசத்திற்கு அழைத்தார்"},
  {ref:"Gen 12:4",en:"Abraham departs at 75 years old in faith",ta:"ஆபிரகாம் 75 வயதில் விசுவாசத்துடன் புறப்பட்டான்"},
  {ref:"Gen 13:14",en:"God shows Abraham the land of Canaan as his inheritance",ta:"தேவன் கானான் தேசத்தை ஆபிரகாமுக்கு காண்பித்தார்"},
  {ref:"Gen 15:5",en:"God shows Abraham the stars and promises countless descendants",ta:"தேவன் நட்சத்திரங்களை காட்டி எண்ணற்ற சந்ததி வாக்குறுதி அளித்தார்"},
  {ref:"Gen 17:5",en:"God changes Abram's name to Abraham — father of many nations",ta:"தேவன் அவன் பெயரை ஆபிரகாம் என்று மாற்றினார்"},
  {ref:"Gen 18:10",en:"God promises a son within a year — Sarah laughs",ta:"ஒரு வருடத்தில் குமாரன் பிறப்பான் என்று வாக்குறுதி — சாரா சிரித்தாள்"},
  {ref:"Gen 21:2",en:"Isaac born when Abraham is 100 and Sarah is 90",ta:"ஆபிரகாமுக்கு 100, சாராளுக்கு 90 வயதில் ஈசாக்கு பிறந்தான்"},
  {ref:"Gen 22:2",en:"God commands Abraham to sacrifice Isaac on Mount Moriah",ta:"மோரியா மலையில் ஈசாக்கை பலியிட தேவன் கட்டளை கொடுத்தார்"},
  {ref:"Gen 22:13",en:"God provides a ram instead — Abraham names the place 'The LORD provides'",ta:"தேவன் ஒரு ஆட்டை கொடுத்தார் — ஆபிரகாம் அந்த இடத்திற்கு 'தேவன் வழங்குவார்' என்று பெயரிட்டான்"},
  {ref:"Gen 22:17",en:"God blesses Abraham — through his seed all nations will be blessed",ta:"தேவன் ஆபிரகாமை ஆசீர்வதித்தார் — அவன் சந்ததியால் எல்லா ஜாதிகளும் ஆசீர்வதிக்கப்படும்"}
 ],
 verses:[
  {ref:"Genesis 15:6",en:"Abraham believed God, and it was counted to him as righteousness.",ta:"ஆபிரகாம் தேவனை விசுவாசித்தான், அது அவனுக்கு நீதியாக எண்ணப்பட்டது."},
  {ref:"Genesis 22:14",en:"Abraham called the name of that place 'The LORD will provide'.",ta:"ஆபிரகாம் அந்த இடத்திற்கு 'கர்த்தர் வழங்குவார்' என்று பெயரிட்டான்."},
  {ref:"Hebrews 11:8",en:"By faith Abraham obeyed when he was called to go out, not knowing where he was going.",ta:"விசுவாசத்தினால் ஆபிரகாம், எங்கே போகிறான் என்று அறியாமல் கீழ்படிந்து புறப்பட்டான்."},
  {ref:"Romans 4:3",en:"Abraham believed God and it was credited to him as righteousness.",ta:"ஆபிரகாம் தேவனை நம்பினான், அது அவனுக்கு நீதியாக கணிக்கப்பட்டது."},
  {ref:"Galatians 3:9",en:"Those who have faith are blessed along with Abraham, the man of faith.",ta:"விசுவாசமுள்ளவர்கள் விசுவாசியான ஆபிரகாமோடு ஆசீர்வதிக்கப்படுவார்கள்."}
 ],
 lessons_en:[
  "Sometimes God asks us to leave what is comfortable — Abraham left his home without knowing where he was going, because he trusted God's plan.",
  "God's promises can seem impossible — but nothing is too hard for God! He gave Abraham a son when it seemed completely impossible.",
  "Faith means trusting God even when you do not understand — Abraham did not know where he was going, but he went anyway.",
  "God always provides — when Abraham trusted God on the mountain, God provided the ram at just the right moment.",
  "One person's faith can change the world — Abraham's faith touched billions of people across thousands of years!"
 ],
 lessons_ta:[
  "சில நேரங்களில் தேவன் சௌகரியத்தை விட்டு வர சொல்வார் — ஆபிரகாம் எங்கே போவான் என்று தெரியாமல் புறப்பட்டான்.",
  "தேவனின் வாக்குறுதிகள் சாத்தியமற்றதுபோல் தெரியலாம் — ஆனால் தேவனுக்கு எதுவும் கடினமில்லை!",
  "விசுவாசம் என்பது புரியாவிட்டாலும் நம்புவது — ஆபிரகாம் புரியாவிட்டாலும் கீழ்படிந்தான்.",
  "தேவன் எப்போதும் வழங்குகிறார் — ஆபிரகாம் நம்பினபோது சரியான நேரத்தில் தேவன் வழி செய்தார்.",
  "ஒருவரின் விசுவாசம் உலகை மாற்றலாம் — ஆபிரகாமின் விசுவாசம் கோடான கோடி மக்களை தொட்டது!"
 ]
},
{id:"moses",name:"Moses",ta_name:"மோசே",emoji:"🔥",color:"#8a1a1a",era:"Exodus",testament:"OT",
 tagline_en:"The Leader Who Freed God's People",tagline_ta:"தேவ ஜனங்களை விடுவித்த தலைவன்",
 summary_en:"Baby Moses was born in Egypt at a terrible time — the cruel King Pharaoh had ordered all baby Hebrew boys to be thrown into the Nile River! Moses' mother loved him so much that she made a little basket from reeds, waterproofed it with tar, and gently placed baby Moses inside. She laid the basket in the Nile River among the tall reeds. Moses' big sister Miriam hid nearby to watch. A princess came to bathe in the river. She heard a baby crying and found the basket. The baby was so cute! 'This must be a Hebrew baby,' she said. Miriam came running: 'Shall I find a Hebrew woman to nurse the baby?' So Moses' own mother got to raise her son — and Moses grew up in Pharaoh's palace as a prince! When Moses grew up, he saw how badly the Egyptians treated the Hebrew people. One day while tending sheep near a mountain, Moses saw an amazing sight — a bush was on fire but was NOT burning up! Then God spoke from the burning bush: 'Moses! I have heard my people crying. You are going to lead them out of Egypt!' Moses was scared. 'But who am I to go to Pharaoh?' God promised to be with him. Moses went and God sent ten amazing plagues to show Pharaoh God's power. Finally Pharaoh let the people go. But then he changed his mind and chased them! The Hebrew people came to the Red Sea — and there was no way across! Moses raised his staff. God sent a mighty wind, and the sea split in two! All the people walked through on dry ground. When the Egyptian army tried to follow, the sea closed over them. God's people were free at last! Moses led the people through the desert for 40 years. God gave Moses the Ten Commandments on Mount Sinai — God's rules for living a good life.",
 summary_ta:"சிறிய மோசே எகிப்தில் ஒரு கஷ்டமான காலத்தில் பிறந்தான். கொடிய பார்வோன் ராஜா ஆண் பிள்ளைகளை எல்லாம் கொல்ல கட்டளை கொடுத்தான்! மோசேயின் அம்மா அவனை நேசித்தாள். ஒரு கூடை செய்து, கீல் பூசி, மோசேயை அதில் வைத்து, நைல் நதியில் மிதக்கவிட்டாள். அம்மாவின் மகள் மிரியாம் தூரத்தில் பார்த்தாள். பார்வோனின் மகள் குளிக்க வந்தாள். அழும் சத்தம் கேட்டு கூடையை எடுத்தாள். குழந்தையை பார்த்து மகிழ்ந்தாள்! மிரியாம் ஓடி வந்தாள்: 'குழந்தைக்கு பால் கொடுக்க ஒரு அம்மாவை கூட்டி வரட்டுமா?' — மோசேயின் சொந்த அம்மாவே அவனை வளர்த்தாள்! மோசே ஒரு இளவரசனாக பார்வோன் அரண்மனையில் வளர்ந்தான். பெரியவனானபோது மக்களின் வேதனையை பார்த்தான். ஒரு நாள் மலையருகே ஒரு புதர் எரிகிறது — ஆனால் தீய்ந்து போவதில்லை! தேவன் பேசினார்: 'மோசே! என் ஜனங்களின் அழுகை கேட்கிறேன். நீ அவர்களை எகிப்திலிருந்து விடுவி!' மோசே பயந்தான். ஆனால் தேவன் உடனிருப்பதாக வாக்குறுதி கொடுத்தார். மோசே பார்வோனிடம் போனான். தேவன் பத்து வாதைகளை அனுப்பினார். கடைசியாக பார்வோன் ஒப்புக்கொண்டான். ஆனால் பின்னர் மனம் மாறி ஜனங்களை துரத்தினான்! சிவந்த கடல் முன்னே — வழியே இல்லை! மோசே கைத்தடியை தூக்கினான். தேவன் காற்று அனுப்பினார், கடல் இரண்டாக பிரிந்தது! எல்லாரும் நடந்தே கடந்தார்கள். சேனை தொடர்ந்தது, கடல் மூடியது. தேவனுடைய ஜனங்கள் சுதந்திரமானார்கள்! மோசே 40 ஆண்டுகள் வழிநடத்தினார். சீனாய் மலையில் தேவன் பத்து கட்டளைகளை கொடுத்தார்.",
 timeline:[
  {ref:"Exo 2:3",en:"Baby Moses placed in a basket in the Nile River",ta:"குழந்தை மோசே கூடையில் நைல் நதியில் விடப்பட்டான்"},
  {ref:"Exo 2:10",en:"Moses rescued and raised as a prince in Pharaoh's palace",ta:"மோசே பார்வோன் அரண்மனையில் இளவரசனாக வளர்ந்தான்"},
  {ref:"Exo 3:2",en:"Moses sees the burning bush that does not burn up",ta:"மோசே தீய்ந்துபோகாத எரியும் புதரை கண்டான்"},
  {ref:"Exo 3:10",en:"God calls Moses: 'I am sending you to Pharaoh'",ta:"தேவன் மோசேயை அழைத்தார்: 'நான் உன்னை பார்வோனிடம் அனுப்புகிறேன்'"},
  {ref:"Exo 7:20",en:"The first plague: Nile River turned to blood",ta:"முதல் வாதை: நைல் நதி இரத்தமாக மாறியது"},
  {ref:"Exo 12:31",en:"Pharaoh tells Moses and the Israelites to leave Egypt",ta:"பார்வோன் மோசேயையும் இஸ்ரவேலரையும் போக சொன்னான்"},
  {ref:"Exo 14:21",en:"Moses stretches his hand — the Red Sea parts",ta:"மோசே கை நீட்டினான் — சிவந்த கடல் பிரிந்தது"},
  {ref:"Exo 14:29",en:"Israelites walk through the sea on dry ground",ta:"இஸ்ரவேலர் வறண்ட நிலத்தில் கடல் வழியே நடந்தார்கள்"},
  {ref:"Exo 20:1",en:"God gives Moses the Ten Commandments on Mount Sinai",ta:"சீனாய் மலையில் தேவன் மோசேவுக்கு பத்து கட்டளைகளை கொடுத்தார்"},
  {ref:"Deut 34:5",en:"Moses dies at 120 years — his eyes were not dim",ta:"மோசே 120 வயதில் மரித்தான் — அவன் கண்கள் குறையவில்லை"}
 ],
 verses:[
  {ref:"Exodus 3:14",en:"God said to Moses: I AM WHO I AM. Say to the Israelites: I AM has sent me to you.",ta:"தேவன் மோசேவிடம் சொன்னார்: நான் இருக்கிறவர். இஸ்ரவேல் பிள்ளைகளிடம் சொல்: இருக்கிறவர் என்னை அனுப்பினார்."},
  {ref:"Exodus 14:14",en:"The LORD will fight for you; you need only to be still.",ta:"கர்த்தர் உங்களுக்காக போர் செய்வார்; நீங்கள் சும்மா இருங்கள்."},
  {ref:"Exodus 20:2",en:"I am the LORD your God, who brought you out of Egypt, out of the land of slavery.",ta:"நான் உன்னை அடிமை வீட்டிலிருந்து விடுவித்து கொண்டுவந்த உன் தேவனாகிய கர்த்தர்."},
  {ref:"Numbers 12:3",en:"Now Moses was a very humble man, more humble than anyone else on the face of the earth.",ta:"மோசே பூமியிலுள்ள யாவரிலும் மிகவும் சாந்தகுணமுள்ளவனாயிருந்தான்."},
  {ref:"Hebrews 11:27",en:"By faith Moses left Egypt, not fearing the king's anger; he persevered because he saw Him who is invisible.",ta:"விசுவாசத்தினால் மோசே ராஜாவின் கோபத்திற்கு பயப்படாமல் எகிப்தை விட்டுப்போனான்."}
 ],
 lessons_en:[
  "God can use anyone — Moses stuttered and was scared, but God still chose him for the most important job in Israel's history!",
  "When God calls you, He equips you — Moses said 'I cannot do this,' but God said 'I will be with you.'",
  "God hears the cries of those who suffer — God told Moses: 'I have heard my people crying. I have seen their suffering.'",
  "Be still and trust God in impossible situations — the Red Sea was in front, the army behind, but God made a way!",
  "God's rules are for our good — the Ten Commandments were not to make life hard but to help people live happily together."
 ],
 lessons_ta:[
  "தேவன் எவரையும் உபயோகிக்க முடியும் — மோசே தடுமாறி பேசினான், ஆனால் தேவன் அவனை தேர்ந்தெடுத்தார்!",
  "தேவன் அழைக்கும்போது தயார்படுத்துகிறார் — மோசே 'என்னால் முடியாது' என்றான், தேவன் 'நான் உன்னோடு இருப்பேன்' என்றார்.",
  "தேவன் துன்பப்படுவோரின் அழுகை கேட்கிறார் — 'என் ஜனங்களின் வேதனையை கண்டேன்' என்றார்.",
  "சாத்தியமற்ற நிலைமையில் அமைதியாய் நம்பு — கடல் முன்னே, சேனை பின்னே, ஆனால் தேவன் வழி செய்தார்!",
  "தேவனின் கட்டளைகள் நமக்கு நன்மைக்காக — பத்து கட்டளைகள் மக்கள் மகிழ்ச்சியாக வாழ உதவுகின்றன."
 ]
},
{id:"david",name:"David",ta_name:"தாவீது",emoji:"👑",color:"#6a1a6a",era:"Kingdom",testament:"OT",
 tagline_en:"The Shepherd Boy Who Became a King",tagline_ta:"ஆடு மேய்த்த சிறுவன் ராஜாவானான்",
 summary_en:"David was the youngest of eight brothers. While his big brothers were important warriors, David was just a shepherd boy looking after fluffy sheep in the hills. But David had a big secret — he loved God with all his heart! While watching the sheep alone at night, he would play his harp and sing songs to God. He even wrote beautiful poems that we still read today in the book of Psalms. One day a giant soldier named Goliath came strutting out of the Philistine army. He was over nine feet tall with armour that weighed more than a small car! Goliath shouted every day: 'Send someone to fight me! I dare you!' All the Israelite soldiers were terrified and ran away. When young David heard this, he was angry. 'Who does this Philistine think he is, defying the armies of the living God?' David told King Saul he would fight Goliath. Saul tried to give David his heavy royal armour, but David said no — he chose five smooth stones from the stream and his slingshot. Goliath laughed when he saw the little shepherd boy. But David said: 'You come with a sword, but I come in the name of the LORD!' David swung his sling. The stone flew straight and hit Goliath right in the forehead. The giant fell down with a thunderous crash. The whole Philistine army ran away! David grew up to become the greatest king Israel ever had. He was not a perfect king — he made big mistakes. But when he did wrong, he was truly sorry and asked God to forgive him. God called David 'a man after my own heart.'",
 summary_ta:"தாவீது எட்டு சகோதரர்களில் இளையவன். அண்ணன்மார் போர் வீரர்கள், தாவீது மேய்ப்பன் சிறுவன். ஆனால் தாவீதுக்கு ஒரு ரகசியம் — அவன் தேவனை முழு இதயத்துடன் நேசித்தான்! தனியே ஆடுகளை மேய்க்கும்போது வீணை வாசித்து தேவனுக்கு பாடினான். இன்றும் நாம் படிக்கும் சங்கீதங்களை எழுதினான். ஒரு நாள் கோலியாத் என்னும் பயங்கரமான சிப்பாய் வந்தான். ஒன்பது அடிக்கும் மேல் உயரம்! ஒவ்வொரு நாளும் கூப்பிட்டான்: 'யாராவது என்னோடு சண்டை போடுவீரா?' இஸ்ரவேல் சேனை பயந்து ஓடியது. தாவீது கேட்டான்: 'உயிருள்ள தேவனின் சேனையை இந்த சிப்பாய் ஏசுகிறான்!' தாவீது ராஜா சவுலிடம் போனான். சவுல் கவசம் கொடுத்தான் — தாவீதுக்கு அது பெரிது. அதனால் அவன் ஓட்டையில் ஐந்து கல்லை எடுத்தான். கோலியாத் சிரித்தான். தாவீது சொன்னான்: 'நீ வாளோடு வருகிறாய், நான் தேவனின் பெயரில் வருகிறேன்!' கவண் சுழற்றினான். கல்லு நேராக கோலியாத்தின் நெற்றியில் பட்டது. ராட்சதன் விழுந்தான்! தாவீது இஸ்ரவேலின் மாபெரும் ராஜாவானான். அவன் தவறுகளும் செய்தான். ஆனால் மனம் வருந்தி மன்னிப்பு கேட்டான். தேவன் அவனை 'என் இதயத்திற்கு ஏற்ற மனிதன்' என்று அழைத்தார்.",
 timeline:[
  {ref:"1 Sam 16:12",en:"Samuel anoints young David as the future king",ta:"சாமுவேல் சிறிய தாவீதை வருங்கால ராஜாவாக அபிஷேகித்தான்"},
  {ref:"1 Sam 16:23",en:"David plays harp for King Saul and soothes his troubled spirit",ta:"தாவீது சவுல் ராஜாவுக்கு வீணை வாசித்தான்"},
  {ref:"1 Sam 17:26",en:"David hears Goliath's challenge and volunteers to fight",ta:"தாவீது கோலியாத்தின் சவாலை கேட்டு சண்டை போட முன்வந்தான்"},
  {ref:"1 Sam 17:49",en:"David's stone hits Goliath — the giant falls",ta:"தாவீதின் கல்லு கோலியாத்தை தாக்கியது — ராட்சதன் விழுந்தான்"},
  {ref:"2 Sam 5:3",en:"David becomes king over all Israel at age 30",ta:"தாவீது 30 வயதில் இஸ்ரவேல் மொத்தத்திற்கும் ராஜாவானான்"},
  {ref:"2 Sam 6:14",en:"David dances before the LORD when the ark is brought to Jerusalem",ta:"உடன்படிக்கை பெட்டி வரும்போது தாவீது தேவன் முன்னே ஆடினான்"},
  {ref:"Psalm 51:10",en:"David prays after his sin: 'Create in me a clean heart, O God'",ta:"பாவத்திற்கு பின் தாவீது மன்றாடினான்: 'சுத்தமான இதயத்தை படைத்தருளும்'"},
  {ref:"2 Sam 7:16",en:"God promises David: your throne will be established forever",ta:"தேவன் தாவீதுக்கு வாக்குறுதி: உன் சிங்காசனம் என்றுமுள்ளதாக இருக்கும்"},
  {ref:"1 Kings 2:10",en:"David dies after reigning 40 years",ta:"தாவீது 40 ஆண்டுகள் ஆண்டு மரித்தான்"},
  {ref:"Acts 13:22",en:"God calls David 'a man after my own heart'",ta:"தேவன் தாவீதை 'என் இதயத்திற்கு ஏற்ற மனிதன்' என்று அழைத்தார்"}
 ],
 verses:[
  {ref:"Psalm 23:1",en:"The LORD is my shepherd; I shall not want.",ta:"கர்த்தர் என் மேய்ப்பர்; எனக்கு குறைவில்லை."},
  {ref:"1 Samuel 17:47",en:"The battle is the LORD's and He will give all of you into our hands.",ta:"யுத்தம் கர்த்தருடையது, அவர் உங்களை எங்கள் கையில் ஒப்புக்கொடுப்பார்."},
  {ref:"Psalm 51:10",en:"Create in me a clean heart, O God, and renew a right spirit within me.",ta:"தேவனே சுத்தமான இதயத்தை எனக்கு உண்டாக்கும், நேரான ஆவியை என்னில் புதுப்பியும்."},
  {ref:"Acts 13:22",en:"God said: I have found in David a man after my own heart, who will do everything I want him to do.",ta:"தேவன் சொன்னார்: என் மனதின்படி செய்யும் என் இதயத்திற்கு ஏற்ற மனிதனை தாவீதில் கண்டேன்."},
  {ref:"Psalm 34:18",en:"The LORD is close to the broken-hearted and saves those who are crushed in spirit.",ta:"கர்த்தர் நொறுங்கின இதயமுள்ளவர்களுக்கு சமீபமாயிருக்கிறார்."}
 ],
 lessons_en:[
  "God looks at the heart, not the outside — God chose David the small shepherd boy over all his tall strong brothers!",
  "God's battles belong to God — David did not say 'I will fight Goliath' but 'The battle belongs to God!'",
  "Even when we fail, we can come back to God — David sinned badly, but his genuine sorrow and prayer brought him back.",
  "Worship keeps your heart soft — David sang to God and played his harp, keeping his heart close to God.",
  "Small things done faithfully prepare you for big things — David was faithful with sheep, so God trusted him with a kingdom."
 ],
 lessons_ta:[
  "தேவன் இதயத்தை பார்க்கிறார் — தேவன் உயரமான அண்ணன்மாரை விட்டு சிறிய மேய்ப்பன் தாவீதை தேர்ந்தெடுத்தார்!",
  "தேவனின் போர்கள் அவருடையது — 'யுத்தம் தேவனுடையது' என்றான் தாவீது.",
  "தவறுசெய்தாலும் தேவனிடம் திரும்பலாம் — தாவீது வருந்தி மன்னிப்பு கேட்டான்.",
  "ஆராதனை இதயத்தை மென்மையாக்கும் — தாவீது தேவனுக்கு பாடினான், தேவனோடு நெருங்கினான்.",
  "சிறிய வேலைகளில் உண்மையாய் இரு — ஆடுகளை கவனித்தவனுக்கு தேவன் ஒரு ராஜ்யத்தை நம்பினார்."
 ]
},
{id:"esther",name:"Esther",ta_name:"எஸ்தர்",emoji:"💜",color:"#6a1a4a",era:"Exile",testament:"OT",
 tagline_en:"The Brave Queen Who Saved Her People",tagline_ta:"தன் ஜனங்களை காத்த தைரியமான ராணி",
 summary_en:"Esther was a young Jewish girl living in a foreign country after her people had been taken captive. She was an orphan raised by her kind cousin Mordecai. Esther was beautiful inside and out. When the great Persian king Ahasuerus was looking for a new queen, Esther was chosen from all the young women of the kingdom — she became queen! But she had a secret: nobody knew she was Jewish. Then something terrible happened. A wicked man named Haman became angry at Mordecai because Mordecai would not bow down to him. Haman was so angry that he made a plan to destroy ALL the Jewish people in the whole kingdom! When Mordecai found out, he sent a message to Queen Esther. He said: 'Maybe you have come to the kingdom for such a time as this!' Esther was terrified. Going to see the king without being called was punishable by death! But Esther prayed and fasted for three days. Then she said something brave: 'If I perish, I perish — but I will go to the king!' She put on her royal robes and walked bravely into the king's throne room. The king held out his golden sceptre — she was safe! Through her clever plan and brave actions, Esther exposed Haman's evil plot. Haman was punished and the Jewish people were saved. Esther teaches us that God can place us exactly where we need to be to help others.",
 summary_ta:"எஸ்தர் ஒரு இளம் யூத பெண். அவள் அனாதை, தன் உறவினன் மொர்தெகாய் அவளை வளர்த்தான். எஸ்தர் மிகவும் அழகானவள். பெரிய பாரசீக ராஜா அகஸ்வேரு புதிய ராணி தேடினார். நாடு முழுவதும் இளம் பெண்கள் கொண்டு வரப்பட்டனர். எஸ்தர் தேர்வு செய்யப்பட்டாள் — ராணியானாள்! ஆனால் ஒரு ரகசியம்: அவள் யூதர் என்று யாருக்கும் தெரியாது. பிறகு ஒரு கேடான மனிதன் ஆமான் மொர்தெகாயை வெறுத்தான். ஆமான் யூத ஜனங்களை எல்லாரையும் கொல்ல சதி திட்டம் போட்டான்! மொர்தெகாய் எஸ்தருக்கு செய்தி அனுப்பினான்: 'இந்த நேரத்திற்காகவே நீ ராணியானாயோ!' எஸ்தர் பயந்தாள். ராஜா அழைக்காமல் போனால் மரணதண்டனை! ஆனால் மூன்று நாள் உபவாசம் இருந்தாள், ஜெபித்தாள். பிறகு தைரியமாக சொன்னாள்: 'நான் மரித்தாலும் மரிப்பேன் — ஆனால் போவேன்!' ராஜாவின் சிம்மாசன அறைக்கு நடந்தாள். ராஜா தன் தங்க செங்கோலை நீட்டினார் — அவள் பாதுகாப்பாக இருந்தாள்! எஸ்தரின் தைரியத்தால் ஆமானின் சதி வெளிப்பட்டது. ஆமான் தண்டிக்கப்பட்டான். யூத ஜனங்கள் காப்பாற்றப்பட்டார்கள்!",
 timeline:[
  {ref:"Est 2:7",en:"Esther, an orphan, raised by her cousin Mordecai",ta:"அனாதையான எஸ்தர் தன் உறவினன் மொர்தெகாயால் வளர்க்கப்பட்டாள்"},
  {ref:"Est 2:17",en:"Esther chosen as queen of Persia",ta:"எஸ்தர் பாரசீகத்தின் ராணியாக தேர்வு செய்யப்பட்டாள்"},
  {ref:"Est 3:6",en:"Wicked Haman plots to destroy all Jewish people",ta:"தீய ஆமான் யூதர்களை அழிக்க சதி திட்டம் போட்டான்"},
  {ref:"Est 4:13",en:"Mordecai urges Esther: maybe you came to the kingdom for such a time as this",ta:"மொர்தெகாய் கேட்டான்: இந்த நேரத்திற்காகவே நீ ராணியானாயோ?"},
  {ref:"Est 4:16",en:"Esther prays and fasts for three days",ta:"எஸ்தர் மூன்று நாள் ஜெபித்து உபவாசம் இருந்தாள்"},
  {ref:"Est 4:16",en:"Esther says: If I perish, I perish — I will go to the king",ta:"எஸ்தர் சொன்னாள்: நான் மரித்தாலும் மரிப்பேன், ராஜாவிடம் போவேன்"},
  {ref:"Est 5:2",en:"King extends the golden sceptre to Esther — she is safe",ta:"ராஜா தன் தங்க செங்கோலை நீட்டினார் — எஸ்தர் பாதுகாப்பாக இருந்தாள்"},
  {ref:"Est 7:6",en:"Esther exposes Haman's wicked plot to the king",ta:"எஸ்தர் ராஜாவிடம் ஆமானின் சதியை வெளிப்படுத்தினாள்"},
  {ref:"Est 8:17",en:"The Jewish people are saved throughout all the provinces",ta:"யூத ஜனங்கள் எல்லா நாடுகளிலும் காப்பாற்றப்பட்டார்கள்"},
  {ref:"Est 9:22",en:"The feast of Purim established to celebrate deliverance",ta:"விடுதலையை கொண்டாட புரிம் பண்டிகை நிறுவப்பட்டது"}
 ],
 verses:[
  {ref:"Esther 4:14",en:"Who knows whether you have not come to the kingdom for such a time as this?",ta:"இந்த நேரத்திற்காகவே நீ ராஜ்யத்திற்கு வந்தாயோ என்று யார் அறிவார்?"},
  {ref:"Esther 4:16",en:"I will go to the king, even though it is against the law. And if I perish, I perish.",ta:"ஆகாத போதிலும் ராஜாவிடம் போவேன். நான் மரித்தாலும் மரிப்பேன்."},
  {ref:"Proverbs 31:25",en:"She is clothed with strength and dignity; she can laugh at the days to come.",ta:"பலமும் கனமும் அவளுடைய உடையாகும்; வருங்காலத்தைக் குறித்து அவள் சிரிக்கிறாள்."},
  {ref:"Joshua 1:9",en:"Be strong and courageous. Do not be afraid; for the LORD your God will be with you.",ta:"பலமாயிரு தைரியமாயிரு. தேவன் உன்னோடே இருக்கிறார் என்று பயப்படாதே."},
  {ref:"Isaiah 41:10",en:"Fear not, for I am with you; be not dismayed, for I am your God.",ta:"பயப்படாதே, நான் உன்னோடிருக்கிறேன்; கலங்காதே, நான் உன் தேவன்."}
 ],
 lessons_en:[
  "God can place you in the right place at the right time — Esther became queen exactly when her people needed her most!",
  "Prayer gives you courage for scary situations — Esther prayed and fasted three days, then walked boldly into the king's court.",
  "Do not be silent when you can help — Esther could have stayed safe and quiet, but she chose to speak up for others.",
  "Being brave does not mean not being scared — Esther was terrified, but she did the right thing anyway!",
  "God cares for the ones nobody else notices — Esther was an orphan girl, a foreigner, but God had a great plan for her life."
 ],
 lessons_ta:[
  "தேவன் சரியான நேரத்தில் சரியான இடத்தில் வைப்பார் — எஸ்தர் தன் ஜனங்களுக்கு தேவையான நேரத்தில் ராணியானாள்!",
  "ஜெபம் தைரியம் கொடுக்கும் — மூன்று நாள் ஜெபித்த பின்னர் எஸ்தர் தைரியமாக நடந்தாள்.",
  "உதவ முடியும்போது அமைதியாய் இருக்காதே — எஸ்தர் பேசினாள், ஜனங்கள் காப்பாற்றப்பட்டார்கள்.",
  "தைரியமாய் இருப்பது பயமில்லாமல் இருப்பது அல்ல — எஸ்தர் பயந்தாள், ஆனாலும் சரியான காரியம் செய்தாள்.",
  "தேவன் யாரும் கவனிக்காதவர்களை கவனிக்கிறார் — அனாதை பெண்ணுக்கு தேவன் பெரிய திட்டம் வைத்திருந்தார்."
 ]
},
{id:"daniel",name:"Daniel",ta_name:"தானியேல்",emoji:"🦁",color:"#1a4a6a",era:"Exile",testament:"OT",
 tagline_en:"The Boy Who Never Gave Up on God",tagline_ta:"தேவனை ஒருபோதும் விடாத சிறுவன்",
 summary_en:"Daniel was a young Jewish boy when enemy soldiers came and took him far away from his home to the great city of Babylon. The king wanted the smartest Jewish boys to learn Babylonian ways and serve in his palace. Daniel was chosen! But even in this strange foreign land, Daniel decided he would keep trusting God and living by God's rules. Daniel and his three friends refused to eat the king's food because it was not right according to God's laws. They asked to eat only vegetables and water for ten days as a test. After ten days they looked healthier than all the other boys! God also gave Daniel a special gift — the ability to understand dreams and visions. When no wise man could explain the king's strange dream, Daniel prayed and God revealed the answer. The king was amazed! But Daniel's greatest test came much later. New rulers made a law: no one was allowed to pray to anyone except the king — for thirty days! Daniel knew about this law. But three times every day, just as he had always done, Daniel went to his room, opened his window toward Jerusalem, knelt down, and prayed to God. The jealous officials reported Daniel to the king. Even though the king liked Daniel, the law could not be changed — Daniel was thrown into the lions' den! The king spent a sleepless night worrying. At dawn he rushed to the den: 'Daniel! Did your God save you?' And Daniel's voice came back: 'My God sent His angel and shut the lions' mouths!' Daniel came out without a scratch. God had protected him!",
 summary_ta:"தானியேல் ஒரு இளம் யூத சிறுவன். எதிரிகள் அவனை பாபிலோனுக்கு கொண்டு போனார்கள். ராஜா புத்திசாலி யூத சிறுவர்களை தேடினான். தானியேல் தேர்வு செய்யப்பட்டான். ஆனால் இந்த அன்னிய தேசத்திலும் தானியேல் தேவனை நம்புவதாக தீர்மானித்தான். அவனும் மூன்று நண்பர்களும் ராஜாவின் உணவை சாப்பிட மறுத்தார்கள் — தேவனின் கட்டளைகளுக்கு எதிராக இருந்தது. பத்து நாள் காய்கறி மட்டும் சாப்பிட்டார்கள். பத்து நாளுக்கு பின்னர் அவர்கள் மற்றவர்களை விட ஆரோக்கியமாக காணப்பட்டார்கள்! தேவன் தானியேலுக்கு கனவுகளை புரிந்துகொள்ளும் ஆற்றல் கொடுத்தார். ஒரு முறை ஒருவருக்கும் விளக்க முடியாத கனவை தானியேல் விளக்கினான். ராஜா ஆச்சரியப்பட்டான்! ஆனால் மிகவும் கடினமான சோதனை வந்தது. புது ராஜா ஒரு கட்டளை போட்டான்: முப்பது நாள் ராஜாவை தவிர வேறு யாரையும் வணங்கக்கூடாது! தானியேல் தெரிந்தும் ஒவ்வொரு நாளும் மூன்று முறை ஜெருசலேமை நோக்கி ஜன்னல் திறந்து ஜெபித்தான். அவனை சிங்கக் குழியில் போட்டார்கள்! ராஜா இரவு முழுவதும் தூக்கம் வரவில்லை. விடியற்காலையில் ஓடி வந்தான்: 'தானியேலே! உன் தேவன் உன்னை காப்பாற்றினாரா?' தானியேலின் குரல் வந்தது: 'தேவன் தன் தூதனை அனுப்பினார், சிங்கங்களின் வாயை மூடினார்!' தானியேல் அழியாமல் வெளியே வந்தான்!",
 timeline:[
  {ref:"Dan 1:3",en:"Daniel taken captive to Babylon as a young boy",ta:"தானியேல் சிறு வயதில் பாபிலோனுக்கு சிறைப்பட்டான்"},
  {ref:"Dan 1:8",en:"Daniel resolves not to defile himself with the king's food",ta:"தானியேல் ராஜாவின் உணவால் தன்னை தீட்டுப்படுத்தாமல் இருக்க தீர்மானித்தான்"},
  {ref:"Dan 1:15",en:"After ten days Daniel looks healthier than all the others",ta:"பத்து நாளுக்கு பின்னர் தானியேல் மற்றவர்களை விட ஆரோக்கியமாக காணப்பட்டான்"},
  {ref:"Dan 2:47",en:"King Nebuchadnezzar bows before Daniel after the dream is interpreted",ta:"கனவின் விளக்கத்திற்கு பின்னர் ராஜா தானியேல் முன்னே வணங்கினான்"},
  {ref:"Dan 3:25",en:"Daniel's three friends survive the fiery furnace — a fourth man seen walking with them",ta:"தானியேலின் மூன்று நண்பர்கள் அக்கினி கொல்லில் பாதுகாக்கப்பட்டனர்"},
  {ref:"Dan 5:17",en:"Daniel interprets the writing on the wall for King Belshazzar",ta:"தானியேல் பெல்ஷாத்சார் ராஜாவுக்கு சுவரின் எழுத்தை விளக்கினான்"},
  {ref:"Dan 6:10",en:"Daniel prays three times a day despite the king's decree",ta:"ராஜாவின் கட்டளை இருந்தும் தானியேல் ஒவ்வொரு நாளும் மூன்று முறை ஜெபித்தான்"},
  {ref:"Dan 6:16",en:"Daniel thrown into the lions' den",ta:"தானியேல் சிங்கக் குழியில் போடப்பட்டான்"},
  {ref:"Dan 6:22",en:"Daniel's God shut the lions' mouths — Daniel unharmed",ta:"தேவன் சிங்கங்களின் வாயை மூடினார் — தானியேல் காயமில்லாமல் இருந்தான்"},
  {ref:"Dan 6:26",en:"King decrees all must fear the God of Daniel",ta:"ராஜா தானியேலின் தேவனை அஞ்ச வேண்டும் என்று கட்டளை கொடுத்தான்"}
 ],
 verses:[
  {ref:"Daniel 6:22",en:"My God sent His angel and shut the mouths of the lions. They have not hurt me.",ta:"என் தேவன் தன் தூதனை அனுப்பி சிங்கங்களின் வாயை மூடினார். அவை என்னை காயப்படுத்தவில்லை."},
  {ref:"Daniel 1:8",en:"Daniel resolved that he would not defile himself with the king's food or wine.",ta:"தானியேல் ராஜாவின் ஆகாரத்தினாலும் திராட்சரசத்தினாலும் தன்னை தீட்டுப்படுத்தாமல் இருக்க தன் இருதயத்தில் தீர்மானித்தான்."},
  {ref:"Daniel 6:10",en:"Three times a day Daniel got down on his knees and prayed, giving thanks to his God.",ta:"தானியேல் தன் வீட்டில் தினசரி மூன்று வேளை முழந்தாளிட்டு தன் தேவனை ஜெபித்து நன்றி சொன்னான்."},
  {ref:"Psalm 56:3",en:"When I am afraid, I put my trust in you.",ta:"நான் பயப்படும் நாளிலே உம்மை நம்புவேன்."},
  {ref:"Proverbs 3:5",en:"Trust in the LORD with all your heart and lean not on your own understanding.",ta:"உன் முழு இருதயத்தோடும் கர்த்தரை நம்பு; உன் சொந்த புத்திக்கு கண்டு சாயாதே."}
 ],
 lessons_en:[
  "Stand firm even when you are far from home — Daniel was in a foreign land, but he never forgot who he was or whose he was.",
  "Small faithfulness leads to big faith — Daniel was faithful in little things like his food, so God trusted him with big things.",
  "Prayer is not something to stop doing when it gets dangerous — Daniel prayed three times a day even when it could have cost him his life!",
  "God can close the mouths of lions — God protected Daniel completely. No matter how scary your situation, God is bigger!",
  "One person who stands for God can change a whole nation — because of Daniel, a pagan king declared that everyone must fear the God of Daniel."
 ],
 lessons_ta:[
  "வீட்டிலிருந்து தூரமாக இருந்தாலும் உறுதியாக இரு — தானியேல் அன்னிய தேசத்தில் தேவனை மறக்கவில்லை.",
  "சிறிய உண்மைத்தன்மை பெரிய விசுவாசத்திற்கு வழி செய்யும் — சிறிய விஷயங்களில் உண்மையாய் இருந்தான்.",
  "ஆபத்தான நேரத்தில் ஜெபத்தை நிறுத்தாதே — மரண தண்டனை கட்டளை இருந்தும் தானியேல் ஜெபித்தான்!",
  "தேவன் சிங்கங்களின் வாயை மூட முடியும் — எந்த அச்சமான நிலைமையிலும் தேவன் பெரியவர்!",
  "தேவனுக்காக நிற்கும் ஒருவர் ஒரு தேசத்தையே மாற்றலாம் — தானியேலின் காரணமாக ராஜா தேவனை கெளரவித்தான்."
 ]
},
{id:"mary",name:"Mary",ta_name:"மரியாள்",emoji:"🕊️",color:"#2a4a8a",era:"New Testament",testament:"NT",
 tagline_en:"The Mother of Jesus",tagline_ta:"இயேசுவின் அன்னை",
 summary_en:"Mary was a young woman living in the small town of Nazareth. She was engaged to a carpenter named Joseph. One ordinary day, something extraordinary happened — an angel named Gabriel suddenly appeared! Mary was frightened. Gabriel said: 'Do not be afraid, Mary! God has chosen you for the greatest honour anyone has ever received. You will have a baby, and He will be the Son of God! You will name Him Jesus, which means Saviour.' Mary was amazed and a little confused — how could this happen? But she trusted God completely. She said these beautiful words: 'I am the LORD's servant. Let it happen just as you have said.' Mary went to visit her relative Elizabeth, who was also having a miracle baby named John. When Mary arrived, baby John leaped for joy in Elizabeth's womb! Elizabeth said: 'Blessed are you among women!' Mary burst into a beautiful song of praise to God. When the time came, Mary and Joseph had to travel to Bethlehem for a census. It was a long, hard journey. When they arrived, every inn was full. The baby Jesus was born in a stable, wrapped in cloth, and laid in a feeding trough. Angels sang in the sky! Shepherds came running. Wise men came with gifts of gold, frankincense, and myrrh. Mary kept all these things in her heart. She raised Jesus with love and faith. She watched Him grow in wisdom. She was there when He did His first miracle at a wedding. And she stood at the cross when He died, her heart breaking. But three days later came the greatest joy — Jesus rose from the dead!",
 summary_ta:"மரியாள் நாசரேத் என்னும் சிறிய ஊரில் வாழ்ந்தாள். யோசேப்பு என்னும் தச்சனுக்கு நிச்சயிக்கப்பட்டிருந்தாள். ஒரு சாதாரண நாளில் வித்தியாசமான ஒன்று நடந்தது — காபிரியேல் என்ற தூதன் தோன்றினான்! மரியாள் பயந்தாள். தூதன் சொன்னான்: 'மரியாளே, பயப்படாதே! தேவன் உன்னை தேர்ந்தெடுத்தார். உனக்கு ஒரு குழந்தை பிறக்கும் — அவர் தேவனுடைய குமாரன்! அவருக்கு இயேசு என்று பெயரிடு, அதாவது இரட்சகன்.' மரியாள் ஆச்சரியப்பட்டாள். ஆனால் தேவனை நம்பினாள். அழகான வார்த்தைகள் சொன்னாள்: 'நான் ஆண்டவரின் அடிமை. உம்முடைய வார்த்தையின்படியே ஆகட்டும்.' மரியாள் தன் உறவினள் எலிசபெத்தை பார்க்க போனாள். மரியாள் வந்தபோது எலிசபெத்தின் வயிற்றில் யோவான் சந்தோஷத்தில் குதித்தான்! எலிசபெத்: 'பெண்களுக்குள் ஆசீர்வதிக்கப்பட்டவள் நீயே!' மரியாள் தேவனை துதித்து பாடினாள். பெத்லகேம் பயணம் கஷ்டமாக இருந்தது. விடுதிகளில் இடமில்லை. ஒரு தொழுவத்தில் இயேசு பிறந்தார். தூதர்கள் பாடினார்கள்! மேய்ப்பர்கள் ஓடி வந்தார்கள். ஞானிகள் பரிசுகள் கொண்டு வந்தார்கள். மரியாள் இவற்றை தன் இதயத்தில் வைத்தாள். அன்போடு இயேசுவை வளர்த்தாள். ஒரு திருமணத்தில் முதல் அற்புதம் நடந்தது. கடைசியாக சிலுவையடியில் நின்றாள், இதயம் உடைந்தது. ஆனால் மூன்று நாளுக்கு பின்னர் — இயேசு உயிர்த்தெழுந்தார்!",
 timeline:[
  {ref:"Luke 1:26",en:"Angel Gabriel appears to Mary in Nazareth",ta:"காபிரியேல் தூதன் நாசரேத்தில் மரியாளுக்கு தோன்றினான்"},
  {ref:"Luke 1:38",en:"Mary says: I am the Lord's servant — let it happen as you said",ta:"மரியாள் சொன்னாள்: நான் ஆண்டவரின் அடிமை — உம் வார்த்தையின்படி ஆகட்டும்"},
  {ref:"Luke 1:46",en:"Mary sings the Magnificat — her song of praise",ta:"மரியாள் மகிமைப்படுத்துதல் பாடல் பாடினாள்"},
  {ref:"Luke 2:7",en:"Jesus born in Bethlehem, laid in a manger",ta:"இயேசு பெத்லகேமில் பிறந்தார், முசல்தொட்டியில் வைக்கப்பட்டார்"},
  {ref:"Luke 2:19",en:"Mary treasured all these things, pondering them in her heart",ta:"மரியாள் இவை அனைத்தையும் தன் இதயத்தில் வைத்தாள்"},
  {ref:"Luke 2:41",en:"Mary and Joseph find 12-year-old Jesus in the Temple",ta:"12 வயது இயேசுவை கோவிலில் தேடி கண்டார்கள்"},
  {ref:"John 2:5",en:"Mary tells the servants at Cana: Do whatever He tells you",ta:"கானா திருமணத்தில் மரியாள்: அவர் சொல்வதை செய்யுங்கள்"},
  {ref:"John 19:25",en:"Mary stands at the foot of the cross",ta:"மரியாள் சிலுவையடியில் நின்றாள்"},
  {ref:"John 20:16",en:"The risen Jesus appears to those near the empty tomb",ta:"உயிர்த்த இயேசு காலியான கல்லறை அருகில் தோன்றினார்"},
  {ref:"Acts 1:14",en:"Mary joins the disciples in prayer after the resurrection",ta:"உயிர்த்தெழுதலுக்கு பின்னர் மரியாள் சீஷர்களோடு ஜெபித்தாள்"}
 ],
 verses:[
  {ref:"Luke 1:38",en:"I am the servant of the Lord; let it be to me according to your word.",ta:"இதோ நான் ஆண்டவரின் அடிமை; உமது வார்த்தையின்படி எனக்கு ஆகட்டும்."},
  {ref:"Luke 1:46-47",en:"My soul magnifies the Lord, and my spirit rejoices in God my Saviour.",ta:"என் ஆத்துமா ஆண்டவரை மகிமைப்படுத்துகிறது, என் ஆவி என் இரட்சகராகிய தேவனில் களிகூருகிறது."},
  {ref:"Luke 2:19",en:"Mary treasured up all these things and pondered them in her heart.",ta:"மரியாள் இந்த வார்த்தைகளையெல்லாம் தன் இருதயத்திலே வைத்து சிந்தித்துக்கொண்டிருந்தாள்."},
  {ref:"John 2:5",en:"His mother said to the servants: Do whatever he tells you.",ta:"அவருடைய அன்னை வேலைக்காரர்களை நோக்கி: அவர் உங்களுக்கு சொல்வதெல்லாம் செய்யுங்கள் என்றாள்."},
  {ref:"Luke 1:30",en:"Do not be afraid, Mary; you have found favour with God.",ta:"மரியாளே, பயப்படாதே; தேவனிடத்தில் உனக்கு தயை கிடைத்தது."}
 ],
 lessons_en:[
  "Say yes to God even when it is scary — Mary did not understand everything but she said: 'Let it happen as God says.'",
  "God chooses ordinary people for extraordinary things — Mary was just a young girl from a small town, but God chose her!",
  "Keep precious things in your heart — Mary stored up all the wonderful things God did and thought about them.",
  "Point others to Jesus — at the wedding Mary said: 'Do whatever He tells you.' That is still great advice today!",
  "Even when life is painful, stay close to Jesus — Mary stood at the cross in great pain. Faithfulness means staying even in the hard times."
 ],
 lessons_ta:[
  "பயமாக இருந்தாலும் தேவனுக்கு ஆம் சொல் — மரியாள் புரியாவிட்டாலும் 'உம் வார்த்தையின்படி ஆகட்டும்' என்றாள்.",
  "சாதாரண மக்களை தேவன் அற்புதமான காரியங்களுக்கு தேர்ந்தெடுக்கிறார்!",
  "மதிப்பான விஷயங்களை இதயத்தில் வை — மரியாள் தேவன் செய்தவற்றை இதயத்தில் வைத்தாள்.",
  "மற்றவர்களை இயேசுவிடம் வழிநடத்து — 'அவர் சொல்வதை செய்யுங்கள்' என்றாள் மரியாள்.",
  "வாழ்க்கை வேதனையாக இருக்கும்போதும் இயேசுவருகே நில் — மரியாள் சிலுவையடியில் நின்றாள்."
 ]
},
{id:"peter",name:"Peter",ta_name:"பேதுரு",emoji:"🎣",color:"#1a6a4a",era:"New Testament",testament:"NT",
 tagline_en:"The Fisherman Who Became a Rock",tagline_ta:"மீனவன் பாறையானான்",
 summary_en:"Peter was a big, strong fisherman who worked on the Sea of Galilee with his brother Andrew. He was bold and spoke before thinking — the kind of person who jumps in first and asks questions later! One day while washing his nets on the shore, Peter saw Jesus teaching a crowd. Jesus got into Peter's boat to teach from the water. Afterward Jesus said: 'Row out to deep water and let down your nets for a catch.' Peter was tired from fishing all night without catching anything. But he said: 'Because you say so, I will let down the nets.' Suddenly the nets filled with so many fish they were breaking! Peter fell to his knees: 'Go away from me, Lord — I am a sinful man!' But Jesus smiled and said: 'Do not be afraid. From now on you will fish for people!' Peter left everything and followed Jesus. Peter was one of Jesus' three closest friends. He saw Jesus walk on water — and then Peter tried to walk on water too! He stepped out of the boat and walked toward Jesus on the waves. But when he looked at the storm and got scared, he started to sink. 'Lord, save me!' he cried, and Jesus reached out and caught him. Jesus said: 'Why did you doubt?' At a key moment Jesus asked His disciples: 'Who do you say I am?' Peter answered boldly: 'You are the Christ, the Son of the living God!' Jesus said: 'Good answer, Peter! On this rock I will build my church.' But Peter also failed badly — he denied knowing Jesus three times on the night Jesus was arrested. He wept bitterly. But Jesus did not give up on Peter. After the resurrection, Jesus met Peter on the beach and gave him three chances to say 'I love you.' Peter became the great leader of the first church!",
 summary_ta:"பேதுரு கலிலேயா கடலில் மீன் பிடிக்கும் வலிமையான மனிதன். அவன் சகோதரன் அந்திரேயா. ஒரு நாள் கரையில் வலைகளை கழுவும்போது இயேசு தன் படகில் ஏறி மக்களுக்கு போதித்தார். பிறகு இயேசு சொன்னார்: 'ஆழமான இடத்திற்கு போய் வலை போடுங்கள்.' பேதுரு இரவு முழுவதும் மீன் பிடிக்கவில்லை, களைப்பாக இருந்தான். ஆனால் 'உம் வார்த்தையின்படி வலை போடுவேன்' என்றான். திடீரென்று வலை கிழியும்படி மீன்கள் நிரம்பின! பேதுரு முழந்தாளிட்டு விழுந்தான்: 'ஆண்டவரே, என்னை விட்டு போங்கள் — நான் பாவி!' இயேசு சொன்னார்: 'பயப்படாதே. இனி மனிதரை பிடிப்பவனாவாய்!' பேதுரு எல்லாவற்றையும் விட்டு இயேசுவை பின்பற்றினான். பேதுரு இயேசுவின் மூன்று நெருங்கிய நண்பர்களில் ஒருவன். இயேசு தண்ணீரில் நடந்தார் — பேதுருவும் முயற்சி செய்தான்! படகிலிருந்து இறங்கி அலைகள் மீது நடந்தான். ஆனால் புயலை பார்த்து பயந்தான், மூழ்க தொடங்கினான். 'ஆண்டவரே, என்னை இரட்சியும்!' இயேசு கையை நீட்டி பிடித்தார். 'ஏன் சந்தேகித்தாய்?' என்றார். ஒரு முக்கியமான நேரத்தில் இயேசு கேட்டார்: 'நான் யார் என்று சொல்கிறீர்கள்?' பேதுரு சொன்னான்: 'நீர் கிறிஸ்துவும் உயிருள்ள தேவனுடைய குமாரனுமாவீர்!' இயேசு சொன்னார்: 'இந்த பாறையின்மேல் என் சபையை கட்டுவேன்.' ஆனால் பேதுரு கடைசி இரவில் இயேசுவை மூன்று முறை மறுதலித்தான். கசந்து அழுதான். ஆனால் இயேசு பேதுருவை விடவில்லை. உயிர்த்தெழுந்த பின்னர் கடற்கரையில் சந்தித்தார். 'என்னை நேசிக்கிறாயா?' மூன்று முறை கேட்டார். பேதுரு முதல் திருச்சபையின் மாபெரும் தலைவனானான்!",
 timeline:[
  {ref:"Luke 5:4",en:"Jesus calls Peter to let down the nets — miraculous catch of fish",ta:"இயேசு பேதுருவை வலை போட சொன்னார் — அற்புதமான மீன் பிடிப்பு"},
  {ref:"Mark 1:18",en:"Peter leaves his nets and follows Jesus immediately",ta:"பேதுரு வலைகளை விட்டு உடனே இயேசுவை பின்பற்றினான்"},
  {ref:"Matt 14:29",en:"Peter steps out of the boat and walks on water toward Jesus",ta:"பேதுரு படகிலிருந்து இறங்கி தண்ணீரில் இயேசுவை நோக்கி நடந்தான்"},
  {ref:"Matt 16:16",en:"Peter declares: You are the Christ, the Son of the living God",ta:"பேதுரு அறிவித்தான்: நீர் கிறிஸ்துவும் உயிருள்ள தேவனுடைய குமாரனுமாவீர்"},
  {ref:"John 13:37",en:"Peter declares he will lay down his life for Jesus",ta:"பேதுரு இயேசுவுக்காக உயிரையும் கொடுப்பேன் என்றான்"},
  {ref:"Luke 22:61",en:"Peter denies Jesus three times and weeps bitterly",ta:"பேதுரு மூன்று முறை இயேசுவை மறுதலித்தான், கசந்து அழுதான்"},
  {ref:"John 21:15",en:"Risen Jesus asks Peter three times: Do you love me?",ta:"உயிர்த்த இயேசு பேதுருவிடம் மூன்று முறை கேட்டார்: என்னை நேசிக்கிறாயா?"},
  {ref:"Acts 2:14",en:"Peter preaches at Pentecost — 3000 people believe",ta:"பேதுரு பெந்தகொஸ்தில் பிரசங்கித்தான் — 3000 பேர் விசுவாசித்தார்கள்"},
  {ref:"Acts 12:7",en:"An angel frees Peter from prison",ta:"ஒரு தூதன் பேதுருவை சிறையிலிருந்து விடுவித்தான்"},
  {ref:"Acts 15:7",en:"Peter speaks at the Jerusalem Council about the Gentiles",ta:"பேதுரு எருசலேம் சபையில் புறஜாதியாரைப் பற்றி பேசினான்"}
 ],
 verses:[
  {ref:"Matthew 16:16",en:"You are the Christ, the Son of the living God.",ta:"நீர் கிறிஸ்துவும் ஜீவனுள்ள தேவனுடைய குமாரனுமாவீர்."},
  {ref:"1 Peter 5:7",en:"Cast all your anxiety on him because he cares for you.",ta:"அவர் உங்களை கவலைப்படுகிறார் ஆகையால் உங்கள் கவலையெல்லாவற்றையும் அவர்மேல் வையுங்கள்."},
  {ref:"Luke 5:8",en:"When Simon Peter saw this, he fell at Jesus' knees and said: Go away from me, Lord; I am a sinful man!",ta:"சீமோன் பேதுரு இதை கண்டு இயேசுவின் முழந்தாள்களிலே விழுந்தான்: ஆண்டவரே, என்னை விட்டு போங்கள், நான் பாவியாயிருக்கிறேன்."},
  {ref:"John 21:17",en:"Peter said: Lord, you know all things; you know that I love you.",ta:"பேதுரு சொன்னான்: ஆண்டவரே, நீர் எல்லாவற்றையும் அறிவீர்; நான் உம்மை நேசிக்கிறேன் என்பதை நீர் அறிவீர்."},
  {ref:"Acts 4:12",en:"Salvation is found in no one else, for there is no other name under heaven by which we must be saved.",ta:"வேறொருவரிலும் இரட்சிப்பில்லை; நாம் இரட்சிக்கப்படும்படி வானத்தின் கீழ் மனிதர்களுக்குள்ளே வேறு நாமம் ஒன்றும் கொடுக்கப்படவில்லை."}
 ],
 lessons_en:[
  "Jesus calls ordinary people — Peter was just a fisherman, but Jesus said He would make him a fisher of people!",
  "Courage means stepping out even when it is scary — Peter got out of the boat in the storm. Even though he sank, he tried!",
  "It is okay to fail as long as you come back — Peter denied Jesus and then wept. But he came back, and Jesus forgave him.",
  "One moment of boldness can change thousands of lives — Peter's sermon at Pentecost led 3000 people to believe in Jesus!",
  "Jesus knows our heart — when Peter said 'I love you,' Jesus knew he meant it. Jesus sees past our failures to our heart."
 ],
 lessons_ta:[
  "இயேசு சாதாரண மக்களை அழைக்கிறார் — வெறும் மீனவனை மனிதர்களை பிடிப்பவன் ஆக்கினார்!",
  "தைரியம் என்பது பயமில்லாமல் செய்வதல்ல, பயமுடன் செய்வது — பேதுரு புயலில் படகிலிருந்து இறங்கினான்.",
  "தவறுசெய்தாலும் திரும்பிவரலாம் — பேதுரு மறுதலித்தான், திரும்பினான், இயேசு மன்னித்தார்.",
  "ஒரு தைரியமான நிமிடம் ஆயிரக்கணக்கான வாழ்க்கைகளை மாற்றலாம் — பேதுருவின் ஒரு பிரசங்கம், 3000 பேர் இயேசுவை நம்பினார்கள்!",
  "இயேசு நம் இதயத்தை அறிவார் — 'உம்மை நேசிக்கிறேன்' என்று பேதுரு சொன்னபோது இயேசு அதை அறிந்தார்."
 ]
},
{id:"paul",name:"Paul",ta_name:"பவுல்",emoji:"✉️",color:"#4a1a6a",era:"New Testament",testament:"NT",
 tagline_en:"The Enemy Who Became God's Greatest Messenger",tagline_ta:"எதிரி தேவனுடைய மாபெரும் தூதனானான்",
 summary_en:"Paul's story is one of the most amazing transformations in all of history! He was born as Saul, a very smart Jewish man who knew the scriptures perfectly and was deeply religious. But Saul hated Christians! He thought following Jesus was wrong. He went from house to house dragging Christians to prison. He even watched while a good man named Stephen was stoned to death — and he approved of it! Saul was on his way to Damascus with letters allowing him to arrest more Christians. Suddenly a blazing light from heaven flashed around him and he fell to the ground! He heard a voice: 'Saul! Saul! Why are you persecuting me?' Saul trembled: 'Who are you, Lord?' The voice said: 'I am Jesus, whom you are persecuting.' Saul was blind for three days. He did not eat or drink anything. God sent a man named Ananias to Saul. Ananias was scared — he knew how dangerous Saul was! But God said: 'Go, because I have chosen Saul as my instrument to carry my name to the Gentiles and kings.' Ananias went, laid his hands on Saul, and his sight was restored. Saul was baptised and changed his name to Paul. The man who used to arrest Christians became the greatest preacher of Christ the world has ever seen! Paul travelled thousands of miles across the Roman Empire, starting churches in city after city. He wrote thirteen letters that are now in our Bible. He was beaten, shipwrecked, imprisoned, and stoned — but he never stopped! Paul said: 'I can do all things through Christ who gives me strength.' He also wrote: 'Nothing can separate us from the love of God!' Paul was eventually put in prison in Rome, where he is believed to have been executed. But his letters still speak to us today!",
 summary_ta:"பவுலின் கதை வரலாற்றில் மிகவும் ஆச்சரியமான மாற்றம்! அவன் பெயர் சவுல். மிகவும் படித்த, மதவுணர்வுள்ள யூதன். ஆனால் கிறிஸ்தவர்களை வெறுத்தான்! வீடு வீடாக சென்று கிறிஸ்தவர்களை சிறைப்பட்டினான். ஸ்தேவான் என்னும் நல்ல மனிதன் கல்லால் எறியப்பட்டபோது சவுல் பார்த்தான் — சம்மதித்தான். சவுல் அதிக கிறிஸ்தவர்களை கைது செய்ய தமஸ்குவுக்கு சென்றான். திடீரென்று வானத்திலிருந்து ஒரு ஒளி! தரையில் விழுந்தான்! குரல் வந்தது: 'சவுலே! சவுலே! என்னை ஏன் துன்புறுத்துகிறாய்?' சவுல் நடுங்கினான்: 'ஆண்டவரே, நீர் யார்?' குரல்: 'நான் இயேசு, நீ துன்புறுத்துபவன்.' சவுல் மூன்று நாள் குருடாய் இருந்தான். சாப்பிடவில்லை, குடிக்கவில்லை. அனனியா என்னும் மனிதனை தேவன் அனுப்பினார். அனனியா பயந்தான் — சவுல் எவ்வளவு ஆபத்தானவன் என்று தெரியும். ஆனால் தேவன் சொன்னார்: 'போ, அவனை என் கருவியாக தேர்ந்தெடுத்தேன்.' அனனியா போனான், கைகளை வைத்தான். சவுல் பார்வை திரும்பினது. சவுல் பவுல் ஆனான். கிறிஸ்தவர்களை சிறைப்படுத்தியவன் மிகவும் பெரிய கிறிஸ்தவ பிரசங்கியாரானான்! பவுல் ரோம சாம்ராஜ்யம் முழுவதும் பயணித்தான். நிறைய சபைகளை தொடங்கினான். நம் பைபிளில் உள்ள 13 கடிதங்களை எழுதினான். அடிக்கப்பட்டான், சிறையிலடைக்கப்பட்டான் — ஆனால் நிறுத்தவில்லை! பவுல் சொன்னான்: 'என்னை பலப்படுத்துகிற கிறிஸ்துவினாலே எல்லாவற்றையும் செய்யலாம்.' அவன் கடிதங்கள் இன்றும் நம்மோடு பேசுகின்றன!",
 timeline:[
  {ref:"Acts 7:58",en:"Saul holds the coats of those who stone Stephen",ta:"சவுல் ஸ்தேவான் கல்லெறியப்படும்போது கோட்டுகளை காத்திருந்தான்"},
  {ref:"Acts 9:3",en:"Blinding light flashes from heaven on the road to Damascus",ta:"தமஸ்கு வழியில் வானத்திலிருந்து பிரகாசமான ஒளி தோன்றியது"},
  {ref:"Acts 9:5",en:"Jesus says: I am Jesus, whom you are persecuting",ta:"இயேசு சொன்னார்: நான் இயேசு, நீ துன்புறுத்துகிறவன்"},
  {ref:"Acts 9:18",en:"Saul's sight restored by Ananias — baptised and transformed",ta:"சவுல் பார்வை திரும்பியது, ஞானஸ்நானம் பெற்றான், மாறினான்"},
  {ref:"Acts 13:2",en:"Holy Spirit sets apart Paul and Barnabas for the first missionary journey",ta:"பரிசுத்த ஆவி பவுலையும் பர்னபாவையும் பிரிஷ்டுவித்தார்"},
  {ref:"Acts 16:25",en:"Paul and Silas sing hymns in prison at midnight — earthquake shakes the prison",ta:"பவுலும் சீலாவும் சிறையில் நடுரவிலே பாடினார்கள் — நிலநடுக்கம் வந்தது"},
  {ref:"Acts 17:22",en:"Paul preaches to the philosophers in Athens about the Unknown God",ta:"பவுல் ஆதேனில் தத்துவஞானிகளுக்கு அறியப்படாத தேவனைப் பற்றி பிரசங்கித்தான்"},
  {ref:"Acts 27:44",en:"Paul survives a shipwreck on his way to Rome",ta:"பவுல் ரோமாவுக்கு போகும் வழியில் கப்பல் உடைப்பிலிருந்து தப்பித்தான்"},
  {ref:"Phil 4:13",en:"Paul writes from prison: I can do all things through Christ",ta:"சிறையிலிருந்து பவுல் எழுதினான்: கிறிஸ்துவினாலே எல்லாவற்றையும் செய்யலாம்"},
  {ref:"2 Tim 4:7",en:"Paul's final words: I have fought the good fight, I have finished the race",ta:"பவுலின் இறுதி வார்த்தைகள்: நான் நற்போர் புரிந்தேன், ஓட்டத்தை முடித்தேன்"}
 ],
 verses:[
  {ref:"Philippians 4:13",en:"I can do all this through him who gives me strength.",ta:"என்னை பலப்படுத்துகிற கிறிஸ்துவினாலே எல்லாவற்றையும் செய்யலாம்."},
  {ref:"Romans 8:38-39",en:"Neither death nor life, neither angels nor demons can separate us from the love of God in Christ Jesus.",ta:"மரணமாவது ஜீவனாவது தேவனுடைய அன்பிலிருந்து நம்மை பிரிக்கமாட்டாது."},
  {ref:"Acts 9:5",en:"I am Jesus, whom you are persecuting.",ta:"நான் இயேசு, நீ துன்புறுத்துகிறவன்."},
  {ref:"2 Timothy 4:7",en:"I have fought the good fight, I have finished the race, I have kept the faith.",ta:"நற்போர் புரிந்தேன், ஓட்டத்தை முடித்தேன், விசுவாசத்தை காத்தேன்."},
  {ref:"Galatians 2:20",en:"It is no longer I who live, but Christ who lives in me.",ta:"இனி நான் ஜீவிக்கிறதில்லை, கிறிஸ்துவே என்னில் ஜீவிக்கிறார்."}
 ],
 lessons_en:[
  "Nobody is too far gone for God to change — Saul hated Christians and God still transformed him into the greatest preacher of Christ!",
  "God can use your past for His purpose — Paul knew the scriptures, and God used that knowledge to write much of the New Testament.",
  "Suffering does not stop God's plan — Paul was beaten, imprisoned, and shipwrecked, but he never stopped spreading the good news.",
  "We can do impossible things with God's strength — 'I can do all things through Christ who strengthens me!'",
  "Nothing can separate us from God's love — Paul wrote these words in prison. No matter what happens, God's love never ends!"
 ],
 lessons_ta:[
  "தேவனால் யாரையும் மாற்ற முடியும் — கிறிஸ்தவர்களை வெறுத்த சவுல், பெரிய பிரசங்கியார் ஆனான்!",
  "தேவன் உன் கடந்த காலத்தை பயன்படுத்துவார் — பவுலின் அறிவை தேவன் பைபிள் எழுத பயன்படுத்தினார்.",
  "கஷ்டங்கள் தேவனின் திட்டத்தை நிறுத்தாது — பவுல் துன்பப்பட்டும் நிறுத்தவில்லை.",
  "தேவனின் பலத்தால் சாத்தியமற்றதையும் செய்யலாம் — 'கிறிஸ்துவினாலே எல்லாவற்றையும் செய்யலாம்!'",
  "எதுவும் தேவனின் அன்பிலிருந்து பிரிக்க முடியாது — சிறையிலிருந்து பவுல் எழுதினான். தேவனின் அன்பு ஒருபோதும் முடியாது!"
 ]
},
{id:"jesus",name:"Jesus",ta_name:"இயேசு",emoji:"✝️",color:"#8a4a1a",era:"New Testament",testament:"NT",
 tagline_en:"God's Son Who Came to Save the World",tagline_ta:"உலகை இரட்சிக்க வந்த தேவனுடைய குமாரன்",
 summary_en:"The whole Bible is really one long story about Jesus! From the very first page, where God promises a Saviour, to the very last page, where Jesus says 'I am coming soon' — it is all pointing to Jesus. God loved the world so much that He sent His only Son to come and live with us. Jesus was born as a tiny baby in a stable in Bethlehem. Angels sang! Shepherds ran! Wise men travelled far to bring gifts. Jesus grew up in Nazareth with Mary and Joseph. He was a normal boy who learned carpentry — but He never sinned even once! When Jesus was 30 years old, He was baptised in the River Jordan and the Holy Spirit came down like a dove. Then Jesus went into the desert for 40 days without food. The devil came and tempted Him three times, but Jesus said no every time — using words from the Bible! Jesus chose twelve disciples — ordinary men like fishermen and tax collectors. Then He began doing the most amazing things. He turned water into wine, fed 5000 people with five loaves and two fish, walked on water, healed blind people and deaf people, and even raised dead people back to life! But most wonderfully, Jesus taught us about God's love. He said God loves us like a father loves his children. He told stories — about lost sheep, about a lost son who came home, about a good Samaritan who helped a stranger. Jesus treated everyone with kindness — women, children, sick people, poor people, even tax collectors and sinners that everyone else looked down on. Then came the most important week in all history. Jesus entered Jerusalem riding on a donkey. The crowds cheered! But within days, religious leaders arrested Jesus. He was beaten and crucified on a cross. It was the darkest day ever. But Jesus was dying for OUR mistakes and sins — taking our punishment so we could be forgiven! Three days later, the tomb was empty. Jesus was alive! He appeared to Mary, to His disciples, to more than 500 people. Then He rose up into heaven. But He promised: 'I am with you always, to the very end of the age.' And one day, Jesus is coming back!",
 summary_ta:"முழு பைபிளும் இயேசுவைப் பற்றிய ஒரு நீண்ட கதை! முதல் பக்கத்திலிருந்து — ஒரு மீட்பர் வருவார் என்று வாக்குறுதி — கடைசி பக்கம் வரை — 'நான் சீக்கிரம் வருகிறேன்' — எல்லாம் இயேசுவை சுட்டுகிறது. தேவன் உலகை நேசித்தார், தன் ஒரே குமாரனை அனுப்பினார். இயேசு பெத்லகேம் தொழுவத்தில் குழந்தையாக பிறந்தார். தூதர்கள் பாடினார்கள்! மேய்ப்பர்கள் ஓடினார்கள்! ஞானிகள் பரிசுகள் கொண்டு வந்தார்கள். இயேசு நாசரேத்தில் வளர்ந்தார். தச்சு வேலை கற்றார். ஆனால் ஒரு போதும் பாவம் செய்யவில்லை! 30 வயதில் யோர்தான் நதியில் ஞானஸ்நானம் பெற்றார். பரிசுத்த ஆவி புறாவைப்போல வந்தார். 40 நாள் பாலை வனத்தில் ஜெபித்தார். சாத்தான் மூன்று முறை சோதித்தான், இயேசு ஒவ்வொரு முறையும் பைபிள் வார்த்தைகளால் மறுத்தார்! பன்னிரண்டு சீஷர்களை தேர்ந்தெடுத்தார். பிறகு அற்புதமான காரியங்கள் செய்தார். தண்ணீரை திராட்சைரசமாக மாற்றினார். 5000 பேருக்கு ஐந்து அப்பம் இரண்டு மீனால் உணவிட்டார். தண்ணீரில் நடந்தார். குருடர்களுக்கு பார்வை, செவிடர்களுக்கு கேள்வி, மரித்தவர்களை உயிர்ப்பித்தார்! மிக அழகாக போதித்தார் — தொலைந்த ஆடு, தொலைந்த மகன், நல்ல சமாரியன். எல்லாரையும் அன்போடு நடத்தினார். பிறகு வந்தது மிக முக்கியமான வாரம். இயேசு கழுதையில் ஏறி எருசலேமில் நுழைந்தார். கூட்டம் ஆர்ப்பரித்தது! ஆனால் சில நாட்களில் அவரை கைது செய்தார்கள். சிலுவையில் அறைந்தார்கள். மிகவும் இருண்ட நாள். ஆனால் இயேசு நமது பாவங்களுக்காக மரித்தார் — நாம் மன்னிக்கப்படும்படி! மூன்று நாளுக்கு பின்னர் கல்லறை காலி. இயேசு உயிர்த்தெழுந்தார்! மரியாளுக்கும் சீஷர்களுக்கும் ஐந்நூறு பேருக்கும் தோன்றினார். பிறகு வானம் ஏறினார். வாக்குறுதி கொடுத்தார்: 'உலகத்தின் முடிவுவரை நான் உங்களோடு இருக்கிறேன்.' ஒரு நாள் இயேசு திரும்பி வருவார்!",
 timeline:[
  {ref:"Luke 2:7",en:"Jesus born in a stable in Bethlehem, laid in a manger",ta:"இயேசு பெத்லகேம் தொழுவத்தில் பிறந்தார், முசல்தொட்டியில் வைக்கப்பட்டார்"},
  {ref:"Matt 2:11",en:"Wise men come from the East with gifts of gold, frankincense, and myrrh",ta:"கிழக்கிலிருந்து ஞானிகள் தங்கம், கந்தவர்க்கம், வெள்ளைப்போளம் கொண்டு வந்தார்கள்"},
  {ref:"Luke 3:22",en:"Jesus baptised in the Jordan — Holy Spirit descends like a dove",ta:"யோர்தானில் ஞானஸ்நானம் — பரிசுத்த ஆவி புறாவைப்போல வந்தார்"},
  {ref:"Matt 4:11",en:"Jesus overcomes Satan's three temptations in the desert",ta:"இயேசு பாலை வனத்தில் சாத்தானின் மூன்று சோதனைகளை வென்றார்"},
  {ref:"John 2:11",en:"Jesus performs His first miracle — turns water into wine at Cana",ta:"கானா திருமணத்தில் இயேசு முதல் அற்புதம் செய்தார் — தண்ணீரை திராட்சைரசமாக மாற்றினார்"},
  {ref:"Matt 14:25",en:"Jesus walks on the Sea of Galilee",ta:"இயேசு கலிலேயா கடலில் நடந்தார்"},
  {ref:"John 11:44",en:"Jesus raises Lazarus from the dead — four days in the tomb",ta:"இயேசு நான்கு நாள் கல்லறையில் இருந்த லாசருவை உயிர்ப்பித்தார்"},
  {ref:"Matt 21:8",en:"Jesus enters Jerusalem on a donkey — triumphal entry",ta:"இயேசு கழுதையில் ஏறி எருசலேமில் நுழைந்தார் — ஜனங்கள் ஆர்ப்பரித்தார்கள்"},
  {ref:"Luke 23:46",en:"Jesus dies on the cross: Father, into your hands I commit my spirit",ta:"இயேசு சிலுவையில் மரித்தார்: பிதாவே, உம் கைகளில் என் ஆவியை ஒப்புவிக்கிறேன்"},
  {ref:"Luke 24:6",en:"He is not here; He has risen! Just as He said.",ta:"அவர் இங்கே இல்லை; உயிர்த்தெழுந்தார்! அவர் சொன்னபடியே ஆயிற்று."}
 ],
 verses:[
  {ref:"John 3:16",en:"For God so loved the world that He gave His one and only Son, that whoever believes in Him shall not perish but have eternal life.",ta:"தேவன் உலகை அவ்வளவாய் நேசித்தார், தம்முடைய ஒரே குமாரனை கொடுத்தார்; அவரை விசுவாசிக்கிறவன் கெட்டுப்போகாமல் நித்திய ஜீவனை பெறும்படி."},
  {ref:"John 14:6",en:"I am the way and the truth and the life. No one comes to the Father except through me.",ta:"நான் வழியும் சத்தியமும் ஜீவனுமாயிருக்கிறேன்; என்னை அல்லாமல் ஒருவனும் பிதாவினிடத்தில் வரான்."},
  {ref:"Matthew 11:28",en:"Come to me, all you who are weary and burdened, and I will give you rest.",ta:"வருத்தப்பட்டு சுமை சுமக்கிறவர்களே, எல்லாரும் என்னிடத்தில் வாருங்கள், நான் உங்களுக்கு இளைப்பாறுதல் தருவேன்."},
  {ref:"Luke 24:6",en:"He is not here; He has risen, just as He said.",ta:"அவர் இங்கே இல்லை, உயிர்த்தெழுந்தார்; அவர் சொன்னபடியே ஆயிற்று."},
  {ref:"Matthew 28:20",en:"I am with you always, to the very end of the age.",ta:"இதோ உலகத்தின் முடிவுபரியந்தம் நான் எந்நாளும் உங்களோடு இருக்கிறேன்."}
 ],
 lessons_en:[
  "God loves you so much He gave His best for you — John 3:16 is the whole gospel in one sentence: God loves, God gave, believe, and live!",
  "Jesus understands what it feels like to be human — He was hungry, tired, sad, and tempted. He understands everything you face.",
  "Jesus welcomes everyone — He ate with sinners, healed the sick, blessed children, and talked to women in public when no one else would.",
  "The cross was not the end — when everything seemed lost and dark, God turned it into the greatest victory in history!",
  "Jesus is coming back — He promised, and He keeps His promises. One day every tear will be wiped away and everything will be made new!"
 ],
 lessons_ta:[
  "தேவன் உன்னை மிகவும் நேசிக்கிறார் — யோவான் 3:16 ஒரே வாக்கியத்தில் நற்செய்தி: தேவன் நேசித்தார், கொடுத்தார், நம்பு, வாழு!",
  "இயேசு மனித உணர்வுகளை புரிந்துகொள்கிறார் — அவர் பசித்தார், களைத்தார், துக்கப்பட்டார். நீ அனுபவிப்பதை புரிந்துகொள்கிறார்.",
  "இயேசு எல்லாரையும் வரவேற்கிறார் — பாவிகளோடு சாப்பிட்டார், நோயாளிகளை குணப்படுத்தினார், குழந்தைகளை ஆசீர்வதித்தார்.",
  "சிலுவை முடிவு அல்ல — எல்லாம் தோல்வியாக தோன்றியபோது தேவன் அதை வரலாற்றின் மாபெரும் வெற்றியாக மாற்றினார்!",
  "இயேசு திரும்பி வருவார் — வாக்குறுதி கொடுத்தார், அவர் வாக்குறுதிகளை காக்கிறார். ஒரு நாள் எல்லா கண்ணீரும் துடைக்கப்படும்!"
 ]
}
];
